<script setup lang="ts">
import { computed } from 'vue'
import type { PaymentTool, PaymentTransaction, RewardRule, StoredValueBalance, Trip } from '../types'
import { rewardUsage, storedValueBalance } from '../utils/paymentRewards'

const props = defineProps<{ trip: Trip; tools: PaymentTool[]; rules: RewardRule[]; transactions: PaymentTransaction[]; balances: StoredValueBalance[]; userId: string; canEdit: boolean; memberName: (id: string) => string }>()
const emit = defineEmits<{ addTool: []; editTool: [tool: PaymentTool]; removeTool: [tool: PaymentTool]; toggleTool: [tool: PaymentTool]; addRule: [tool: PaymentTool]; editRule: [rule: RewardRule]; removeRule: [rule: RewardRule]; addTransaction: [tool?: PaymentTool]; editTransaction: [transaction: PaymentTransaction]; removeTransaction: [transaction: PaymentTransaction]; manageBalance: [tool: PaymentTool] }>()
const typeLabel: Record<PaymentTool['type'], string> = { credit_card: '信用卡', debit_card: '簽帳金融卡', electronic_payment: '電子支付', transport_card: '交通卡', cash: '現金', other: '其他' }
const ownTools = computed(() => props.tools.filter((tool) => tool.ownerUserId === props.userId))
const visibleTools = computed(() => ownTools.value)
const activeTransactions = computed(() => props.transactions.filter((item) => item.ownerUserId === props.userId && item.status !== 'cancelled'))
const totals = computed(() => activeTransactions.value.reduce((sum, item) => ({ amount: sum.amount + (item.transactionType === 'purchase' ? item.convertedAmount || item.originalAmount : 0), reward: sum.reward + (item.estimatedRewardAmount || 0), fee: sum.fee + (item.foreignTransactionFee || 0), net: sum.net + (item.estimatedNetRewardAmount || 0) }), { amount: 0, reward: 0, fee: 0, net: 0 }))
function toolRules(tool: PaymentTool) { return props.rules.filter((rule) => rule.paymentToolId === tool.id) }
function toolTransactions(tool: PaymentTool) { return activeTransactions.value.filter((item) => item.paymentToolId === tool.id) }
function toolTotal(tool: PaymentTool) { return toolTransactions(tool).filter((item) => item.transactionType === 'purchase').reduce((sum, item) => sum + (item.convertedAmount || item.originalAmount), 0) }
function toolReward(tool: PaymentTool) { return toolTransactions(tool).reduce((sum, item) => sum + (item.estimatedRewardAmount || 0), 0) }
function toolFee(tool: PaymentTool) { return toolTransactions(tool).reduce((sum, item) => sum + (item.foreignTransactionFee || 0), 0) }
function currentBalance(tool: PaymentTool) { return props.balances.find((item) => item.paymentToolId === tool.id) || storedValueBalance(tool, toolTransactions(tool), 0) }
function isStoredValue(tool: PaymentTool) { return tool.type === 'electronic_payment' || tool.type === 'transport_card' }
function action(command: string, tool: PaymentTool) { if (command === 'transaction') emit('addTransaction', tool); if (command === 'rule') emit('addRule', tool); if (command === 'edit') emit('editTool', tool); if (command === 'toggle') emit('toggleTool', tool); if (command === 'remove') emit('removeTool', tool); if (command === 'balance') emit('manageBalance', tool) }
function transactionAction(command: string, transaction: PaymentTransaction) { if (command === 'edit') emit('editTransaction', transaction); if (command === 'remove') emit('removeTransaction', transaction) }
</script>

<template>
  <section class="payment-page panel">
    <header class="payment-heading"><div><p>PAYMENTS</p><h2>支付與回饋</h2><span>追蹤旅行付款、海外手續費與回饋額度。</span></div><div><el-button v-if="canEdit" class="payment-secondary" @click="emit('addTransaction')">＋ 新增消費</el-button><el-button v-if="canEdit" type="primary" class="payment-primary" @click="emit('addTool')">＋ 新增支付工具</el-button></div></header>
    <div class="payment-summary"><article><span>本趟付款總額</span><strong>{{ trip.currency }} {{ totals.amount.toLocaleString() }}</strong></article><article><span>預估回饋</span><strong>{{ trip.currency }} {{ totals.reward.toLocaleString() }}</strong></article><article><span>海外手續費</span><strong class="is-fee">{{ trip.currency }} {{ totals.fee.toLocaleString() }}</strong></article><article><span>預估淨回饋</span><strong class="is-net">{{ trip.currency }} {{ totals.net.toLocaleString() }}</strong></article></div>
    <section class="payment-tools"><div class="payment-section-title"><h3>我的支付工具</h3><span>{{ ownTools.length }} 項</span></div><div v-if="visibleTools.length" class="tool-grid"><article v-for="tool in visibleTools" :key="tool.id" class="tool-card" :class="{ 'is-inactive': !tool.isActive }"><div class="tool-card-top"><span class="tool-type">{{ typeLabel[tool.type] }}</span><el-dropdown v-if="canEdit" trigger="click" @command="action($event, tool)"><button type="button" class="tool-more" :aria-label="`${tool.name} 更多操作`" title="更多操作">⋯</button><template #dropdown><el-dropdown-menu><el-dropdown-item command="transaction">新增消費</el-dropdown-item><el-dropdown-item command="rule">新增回饋規則</el-dropdown-item><el-dropdown-item v-if="isStoredValue(tool)" command="balance">設定初始餘額</el-dropdown-item><el-dropdown-item command="edit">編輯工具</el-dropdown-item><el-dropdown-item command="toggle">{{ tool.isActive ? '停用工具' : '啟用工具' }}</el-dropdown-item><el-dropdown-item divided command="remove" class="danger-action">刪除工具</el-dropdown-item></el-dropdown-menu></template></el-dropdown></div><h4>{{ tool.name }}</h4><p>{{ tool.issuer || typeLabel[tool.type] }}<template v-if="tool.lastFourDigits">・末四碼 {{ tool.lastFourDigits }}</template></p><small>持有人：{{ memberName(tool.ownerUserId) }}</small><div class="tool-metrics"><span>已刷 <b>{{ trip.currency }} {{ toolTotal(tool).toLocaleString() }}</b></span><span>回饋 <b>{{ trip.currency }} {{ toolReward(tool).toLocaleString() }}</b></span><span>手續費 <b>{{ trip.currency }} {{ toolFee(tool).toLocaleString() }}</b></span></div><div v-for="rule in toolRules(tool).filter((rule) => rule.isActive)" :key="rule.id" class="rule-usage"><div><strong>{{ rule.name }} {{ (rule.totalRate * 100).toFixed(1) }}%</strong><span v-if="rule.requiresRegistration && !rule.registrationCompleted">尚未完成活動登錄</span></div><template v-if="rule.rewardCap || rule.maximumEligibleSpend"><small>回饋已使用 {{ rewardUsage(rule, toolTransactions(tool)).usedRewardAmount.toLocaleString() }}{{ rule.rewardCap ? `／${rule.rewardCap.toLocaleString()}` : '' }}</small><el-progress :percentage="rule.rewardCap ? Math.min(100, rewardUsage(rule, toolTransactions(tool)).usedRewardAmount / rule.rewardCap * 100) : 0" :show-text="false" /><small>約可再刷 {{ rewardUsage(rule, toolTransactions(tool)).canSpend?.toLocaleString() || '不限' }}</small></template></div><div v-if="isStoredValue(tool)" class="stored-balance"><span>目前餘額</span><strong>{{ currentBalance(tool).currency || tool.defaultCurrency }} {{ currentBalance(tool).currentBalance.toLocaleString() }}</strong></div></article></div><div v-else class="payment-empty"><strong>尚未建立支付工具</strong><p>先加入信用卡、電子支付或交通卡，即可追蹤回饋。</p><el-button v-if="canEdit" @click="emit('addTool')">新增第一個支付工具</el-button></div></section>
    <section class="payment-transactions"><div class="payment-section-title"><h3>付款明細</h3><span>{{ activeTransactions.length }} 筆</span></div><div v-if="activeTransactions.length" class="transaction-list"><article v-for="transaction in activeTransactions.slice().sort((a,b) => b.transactionDate.localeCompare(a.transactionDate))" :key="transaction.id" class="transaction-row"><div><strong>{{ transaction.title }}</strong><p>{{ transaction.transactionDate }}・{{ tools.find((tool) => tool.id === transaction.paymentToolId)?.name || '已移除工具' }}<template v-if="transaction.merchant">・{{ transaction.merchant }}</template></p></div><div class="transaction-amount"><b>{{ transaction.originalCurrency }} {{ transaction.originalAmount.toLocaleString() }}</b><small v-if="transaction.estimatedNetRewardAmount">淨回饋 {{ transaction.settlementCurrency || trip.currency }} {{ transaction.estimatedNetRewardAmount.toLocaleString() }}</small></div><el-dropdown v-if="canEdit" trigger="click" @command="transactionAction($event, transaction)"><button class="tool-more" type="button" aria-label="交易更多操作" title="更多操作">⋯</button><template #dropdown><el-dropdown-menu><el-dropdown-item command="edit">編輯交易／退款</el-dropdown-item><el-dropdown-item divided command="remove" class="danger-action">刪除交易</el-dropdown-item></el-dropdown-menu></template></el-dropdown></article></div><div v-else class="payment-empty compact"><strong>尚未有付款紀錄</strong><el-button v-if="canEdit" @click="emit('addTransaction')">新增第一筆消費</el-button></div></section>
  </section>
</template>

<style scoped>
.payment-page{grid-column:1/-1;padding:24px}.payment-heading{display:flex;justify-content:space-between;gap:16px;padding-bottom:18px;border-bottom:1px solid #e5ece7}.payment-heading p{margin:0;color:#df765f;font-size:11px;font-weight:800;letter-spacing:1.2px}.payment-heading h2{margin:3px 0;color:#163b37;font-size:20px}.payment-heading span{color:#6b7d78;font-size:13px}.payment-heading>div:last-child{display:flex;gap:8px}.payment-primary{border:0;background:#123f3a}.payment-secondary{border-color:#bad7ca;color:#276b59}.payment-summary{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px;margin:18px 0}.payment-summary article{display:grid;gap:4px;padding:13px;border:1px solid #e1e8e3;border-radius:12px;background:#fbfcfa}.payment-summary span{color:#6b7d78;font-size:12px}.payment-summary strong{color:#163b37;font-size:16px}.payment-summary .is-fee{color:#bd7041}.payment-summary .is-net{color:#28735e}.payment-section-title{display:flex;align-items:center;justify-content:space-between;margin:21px 0 10px}.payment-section-title h3{margin:0;color:#244a43;font-size:17px}.payment-section-title span{padding:3px 8px;border-radius:999px;background:#edf5f0;color:#387768;font-size:12px;font-weight:700}.tool-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(250px,1fr));gap:12px}.tool-card{display:grid;gap:9px;padding:15px;border:1px solid #dce8e2;border-radius:14px;background:#fff}.tool-card.is-inactive{opacity:.58}.tool-card-top{display:flex;justify-content:space-between;align-items:center}.tool-type{padding:3px 7px;border-radius:999px;background:#eaf4ef;color:#35725f;font-size:11px;font-weight:800}.tool-more{display:grid;width:36px;height:36px;place-items:center;border:0;border-radius:9px;background:transparent;color:#53736a;font-size:20px;cursor:pointer}.tool-more:hover{background:#edf5f0}.tool-card h4{margin:0;color:#163b37;font-size:17px}.tool-card p,.tool-card small{margin:0;color:#6b7d78;font-size:12px}.tool-metrics{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:5px;padding:9px;border-radius:9px;background:#f5f9f6}.tool-metrics span{display:grid;gap:2px;color:#70837c;font-size:11px}.tool-metrics b{color:#244a43;font-size:12px}.rule-usage{display:grid;gap:5px;padding:9px;border:1px solid #e6ece8;border-radius:9px}.rule-usage>div{display:flex;justify-content:space-between;gap:8px}.rule-usage strong{color:#315d53;font-size:12px}.rule-usage span{color:#af6d1d;font-size:11px}.rule-usage small{color:#6b7d78;font-size:11px}.stored-balance{display:flex;justify-content:space-between;padding:9px;border-radius:9px;background:#eef6f1;color:#3c7063;font-size:12px}.stored-balance strong{color:#173d37}.payment-empty{display:grid;justify-items:center;gap:6px;padding:28px;border:1px dashed #c8ddd3;border-radius:13px;text-align:center}.payment-empty strong{color:#244a43}.payment-empty p{margin:0;color:#6b7d78;font-size:13px}.payment-empty.compact{padding:18px}.transaction-list{display:grid;border:1px solid #e1e9e4;border-radius:13px;overflow:hidden}.transaction-row{display:grid;grid-template-columns:minmax(0,1fr) auto 36px;gap:12px;align-items:center;padding:12px;border-bottom:1px solid #edf1ee}.transaction-row:last-child{border-bottom:0}.transaction-row strong{color:#244a43;font-size:14px}.transaction-row p,.transaction-amount small{margin:3px 0 0;color:#71827c;font-size:12px}.transaction-amount{display:grid;text-align:right}.transaction-amount b{color:#173d37;font-size:14px}@media(max-width:600px){.payment-page{padding:16px}.payment-heading{flex-direction:column}.payment-heading>div:last-child{width:100%}.payment-heading .el-button{flex:1;margin:0}.payment-summary{grid-template-columns:repeat(2,minmax(0,1fr));gap:8px}.tool-grid{grid-template-columns:1fr}.transaction-row{grid-template-columns:minmax(0,1fr) 36px}.transaction-amount{grid-column:1;text-align:left}.transaction-row>.el-dropdown{grid-column:2;grid-row:1/3}.tool-more{width:40px;height:40px}.tool-metrics{grid-template-columns:1fr 1fr}}
</style>
